import React from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * Displays comprehensive weather information including current conditions, 
 * essential atmospheric stats, and a 5-day forecast.
 */
export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  // Helper to resolve condition icon if not provided specifically or for primary condition
  const getConditionEmoji = (cond: string) => {
    const normalized = cond.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloudy') || normalized.includes('partly')) return '⛅';
    if (normalized.includes('rain')) return '🌧️';
    if (normalized.includes('snow')) return '❄️';
    if (normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
    return '☁️';
  };

  return (
    <Card 
      shadow="md" 
      padding="var(--ggui-spacing-6, 24px)" 
      radius="xl"
      border
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Header Section: City and Condition */}
        <Stack gap="var(--ggui-spacing-1, 4px)">
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Text 
            variant="bodySmall" 
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {condition}
          </Text>
        </Stack>

        {/* Main Temperature Display */}
        <Stack direction="horizontal" align="center" justify="between">
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {Math.round(temperature)}°{unit}
          </Text>
          <Box padding="var(--ggui-spacing-2, 8px)">
            <Text size="4xl" align="center">
              {getConditionEmoji(condition)}
            </Text>
          </Box>
        </Stack>

        {/* Detailed Stats Row */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="center">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text 
              variant="overline" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              HUMIDITY
            </Text>
            <Text variant="label" weight="semibold">
              {humidity}%
            </Text>
          </Stack>

          <Divider orientation="vertical" margin="var(--ggui-spacing-1, 4px)" />

          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text 
              variant="overline" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              WIND
            </Text>
            <Text variant="label" weight="semibold">
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        <Divider orientation="horizontal" margin="0" />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap="var(--ggui-spacing-2, 8px)" wrap>
          {(forecast ?? []).map((item, index) => (
            <Box 
              key={item.day ?? index} 
              style={{ flex: '1 1 auto', minWidth: '60px' }}
            >
              <Stack align="center" gap="var(--ggui-spacing-2, 8px)">
                <Text 
                  variant="label" 
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {item.day ?? '--'}
                </Text>

                <Text size="lg">
                  {item.icon ?? '☁️'}
                </Text>

                <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                  <Text variant="bodySmall" weight="semibold">
                    {item.high ?? 0}°
                  </Text>
                  <Text 
                    variant="caption" 
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { 
  Container, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Card, 
  Badge, 
  Divider, 
  Spacer 
} from '@ggui-ai/design/primitives';
import { SearchField, FormField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

/**
 * Maps element categories to visual theme tokens.
 */
const getCategoryStyles = (category: string = '') => {
  const cat = category.toLowerCase().trim();

  if (cat.includes('noble-gas')) {
    return { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-900, #0c4a6e)' };
  }
  if (cat.includes('alkali-metal')) {
    return { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-900, #7f1d1d)' };
  }
  if (cat.includes('alkaline-earth')) {
    return { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-900, #78350f)' };
  }
  if (cat.includes('metalloid')) {
    return { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-900, #14532d)' };
  }
  if (cat.includes('halogen')) {
    return { bg: 'var(--ggui-color-info-200, #a5f3fc)', text: 'var(--ggui-color-info-900, #164e63)' };
  }
  if (cat.includes('transition-metal')) {
    return { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', text: 'var(--ggui-color-onSurface, #111827)' };
  }
  if (cat.includes('lanthanide')) {
    return { bg: 'var(--ggui-color-primary-50, #f0f9ff)', text: 'var(--ggui-color-primary-900, #0c4a6e)' };
  }
  if (cat.includes('actinide')) {
    return { bg: 'var(--ggui-color-error-50, #fef2f2)', text: 'var(--ggui-color-error-900, #7f1d1d)' };
  }
  if (cat.includes('post-transition-metal')) {
    return { bg: 'var(--ggui-color-success-50, #f0fdf4)', text: 'var(--ggui-color-success-900, #14532d)' };
  }
  if (cat.includes('nonmetal')) {
    return { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-900, #164e63)' };
  }

  return { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', text: 'var(--ggui-color-onSurface, #111827)' };
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedId, setSelectedId] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase().trim();
    if (!term) return elements;
    return elements.filter(el => 
      (el.name?.toLowerCase().includes(term) ?? false) || 
      (el.symbol?.toLowerCase().includes(term) ?? false)
    );
  }, [elements, searchTerm]);

  const selectedElement = useMemo(() => {
    return elements.find(el => el.atomicNumber === selectedId) || null;
  }, [elements, selectedId]);

  const uniqueCategories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [elements]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Heading level={2}>Periodic Table of Elements</Heading>
          <FormField label="Search Elements" description="Filter by name or symbol (e.g. Gold, Au)">
            <SearchField 
              placeholder="Type to filter..."
              value={searchTerm}
              onChange={setSearchTerm}
            />
          </FormField>
        </Stack>

        {/* Periodic Grid Container */}
        <Box 
          style={{ 
            width: '100%', 
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-2, 8px) 0'
          }}
        >
          <div 
            style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '850px'
            }}
          >
            {elements.map((element) => {
              const isMatch = searchTerm === '' || filteredElements.some(fe => fe.atomicNumber === element.atomicNumber);
              const isSelected = selectedId === element.atomicNumber;
              const styles = getCategoryStyles(element.category);

              return (
                <div
                  key={element.atomicNumber ?? element.symbol}
                  role="button"
                  tabIndex={0}
                  aria-label={`Element ${element.name ?? 'Unknown'}`}
                  onClick={() => element.atomicNumber && setSelectedId(element.atomicNumber)}
                  onKeyDown={(e) => {
                    if ((e.key === 'Enter' || e.key === ' ') && element.atomicNumber) {
                      e.preventDefault();
                      setSelectedId(element.atomicNumber);
                    }
                  }}
                  style={{
                    gridColumn: element.col,
                    gridRow: element.row,
                    aspectRatio: '1/1',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    border: isSelected 
                      ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                      : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    backgroundColor: styles.bg,
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    transition: 'all 200ms ease-in-out',
                    opacity: isMatch ? 1 : 0.3,
                    filter: isMatch ? 'none' : 'grayscale(80%)',
                    zIndex: isSelected ? 10 : 1,
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                    outline: 'none'
                  }}
                >
                  <Text 
                    variant="caption" 
                    style={{ 
                      position: 'absolute', 
                      top: '2px', 
                      left: '4px',
                      fontSize: '10px',
                      color: styles.text,
                      opacity: 0.8
                    }}
                  >
                    {element.atomicNumber}
                  </Text>
                  <Text 
                    variant="bodyLarge" 
                    weight="bold" 
                    style={{ color: styles.text }}
                  >
                    {element.symbol}
                  </Text>
                </div>
              );
            })}
          </div>
        </Box>

        {/* Legend Section */}
        <Card padding="var(--ggui-spacing-4, 16px)" radius="md" border={true} shadow="none">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Element Categories</Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap={true} align="center">
              {uniqueCategories.map(cat => {
                const styles = getCategoryStyles(cat);
                return (
                  <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                    <Box 
                      style={{ 
                        width: '16px', 
                        height: '16px', 
                        backgroundColor: styles.bg, 
                        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
                      }} 
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{cat}</Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>

        {/* Detail Panel */}
        {selectedElement ? (
          <Card 
            padding="var(--ggui-spacing-6, 24px)" 
            radius="xl" 
            shadow="md"
            style={{ 
              backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              animation: 'ggui-slideInUp 300ms ease-out',
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)'
            }}
          >
            <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" align="center" wrap={true}>
              {/* Visual ID */}
              <Stack gap="var(--ggui-spacing-1, 4px)" align="center" style={{ minWidth: '140px' }}>
                <Text 
                  size="4xl" 
                  weight="bold" 
                  color="var(--ggui-color-primary-600, #0284c7)"
                  style={{ lineHeight: 1 }}
                >
                  {selectedElement.symbol ?? ''}
                </Text>
                <Heading level={3} align="center">{selectedElement.name ?? 'Unknown'}</Heading>
              </Stack>

              <Divider orientation="vertical" margin="var(--ggui-spacing-4, 16px)" />

              {/* Data Display */}
              <Box style={{ flex: 1 }}>
                <Stack gap="var(--ggui-spacing-3, 12px)">
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                    <Text weight="semibold" color="var(--ggui-color-onSurface)">{selectedElement.atomicNumber ?? 'N/A'}</Text>
                  </Stack>
                  <Divider margin={0} color="var(--ggui-color-outlineVariant)" />
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text weight="semibold" color="var(--ggui-color-onSurface)">{selectedElement.atomicWeight ?? 'N/A'} u</Text>
                  </Stack>
                  <Divider margin={0} color="var(--ggui-color-outlineVariant)" />
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category</Text>
                    <Badge variant="primary" size="lg" pill={false}>
                      {selectedElement.category ?? 'Unknown'}
                    </Badge>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          </Card>
        ) : (
          <Box padding={24} style={{ backgroundColor: 'var(--ggui-color-surfaceVariant)', borderRadius: 'var(--ggui-shape-radius-lg)' }}>
            <Text align="center" variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
              Select an element from the table above to view its detailed properties.
            </Text>
          </Box>
        )}
      </Stack>
      <Spacer size={32} />
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Divider,
  Badge,
  Button,
  MotionKeyframes,
  Icon,
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

/**
 * Maps chemical category to semantic chart tokens.
 */
const getCategoryColor = (category: string = '') => {
  const cat = category.toLowerCase();
  if (cat.includes('noble')) return 'var(--ggui-color-info-500, #06b6d4)';
  if (cat.includes('halogen')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-success-500, #22c55e)';
  if (cat.includes('alkali-metal')) return 'var(--ggui-color-error-500, #ef4444)';
  if (cat.includes('alkaline-earth')) return 'var(--ggui-color-neutral-600, #4b5563)';
  if (cat.includes('transition')) return 'var(--ggui-color-primary-600, #0284c7)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-primary-400, #38bdf8)';
  if (cat.includes('lanthanide') || cat.includes('actinide')) return 'var(--ggui-color-neutral-400, #9ca3af)';
  return 'var(--ggui-color-neutral-200, #e5e7eb)';
};

/**
 * Maps chemical category to semantic Badge variants.
 */
const getBadgeVariant = (category: string = ''): 'info' | 'warning' | 'success' | 'error' | 'primary' | 'secondary' | 'default' => {
  const cat = category.toLowerCase();
  if (cat.includes('noble')) return 'info';
  if (cat.includes('halogen')) return 'warning';
  if (cat.includes('nonmetal')) return 'success';
  if (cat.includes('alkali-metal')) return 'error';
  if (cat.includes('alkaline') || cat.includes('transition')) return 'primary';
  if (cat.includes('lanthanide') || cat.includes('actinide')) return 'secondary';
  return 'default';
};

/**
 * Interactive Periodic Table Component
 * Displays chemical elements in a standard 18-column grid with detailed inspection views.
 */
export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedSymbol, setSelectedSymbol] = useState<string | null>(null);

  // Compute filtering logic
  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase().trim();
    return elements.map((el) => ({
      ...el,
      matches: !query || 
        (el.name?.toLowerCase().includes(query) ?? false) || 
        (el.symbol?.toLowerCase().includes(query) ?? false)
    }));
  }, [elements, searchQuery]);

  const selectedElement = useMemo(() => {
    return elements.find(el => el.symbol === selectedSymbol);
  }, [elements, selectedSymbol]);

  const uniqueCategories = useMemo(() => {
    const cats = new Set<string>();
    elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header & Search */}
        <Stack direction="horizontal" justify="between" align="end" wrap gap="var(--ggui-spacing-6, 24px)">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={1}>Periodic Table of Elements</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Interactive database of chemical elements. Select a cell to view properties.
            </Text>
          </Stack>
          <Box style={{ width: '100%', maxWidth: '400px' }}>
            <SearchField
              placeholder="Search elements by name or symbol..."
              value={searchQuery}
              onChange={setSearchQuery}
              size="md"
            />
          </Box>
        </Stack>

        {/* Legend Panel */}
        <Card padding="var(--ggui-spacing-4, 16px)" radius="lg" border={true} shadow="none" style={{ backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
          <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" wrap justify="center">
            {uniqueCategories.map(cat => (
              <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                <Box 
                  style={{ 
                    width: 'var(--ggui-spacing-3, 12px)', 
                    height: 'var(--ggui-spacing-3, 12px)', 
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)', 
                    backgroundColor: getCategoryColor(cat) 
                  }} 
                />
                <Text variant="caption" weight="medium" style={{ textTransform: 'capitalize' }}>
                  {cat.replace(/-/g, ' ')}
                </Text>
              </Stack>
            ))}
          </Stack>
        </Card>

        {/* The Table Grid */}
        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <div
            role="grid"
            aria-label="Periodic Table"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(72px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '1200px'
            }}
          >
            {filteredElements.map((el, idx) => {
              const isSelected = el.symbol === selectedSymbol;
              const bgColor = getCategoryColor(el.category);

              return (
                <div
                  key={`${el.symbol}-${idx}`}
                  role="gridcell"
                  tabIndex={0}
                  onClick={() => setSelectedSymbol(isSelected ? null : (el.symbol ?? null))}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      setSelectedSymbol(isSelected ? null : (el.symbol ?? null));
                    }
                  }}
                  aria-label={`${el.name ?? 'Element'} (Atomic Number: ${el.atomicNumber ?? '?'})`}
                  style={{
                    gridRow: el.row ?? 'auto',
                    gridColumn: el.col ?? 'auto',
                    cursor: 'pointer',
                    opacity: el.matches ? 1 : 0.2,
                    filter: el.matches ? 'none' : 'grayscale(100%)',
                    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                    transform: isSelected ? 'scale(1.08)' : 'none',
                    zIndex: isSelected ? 10 : 1,
                    outline: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : 'none',
                    outlineOffset: '2px',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  }}
                >
                  <Card
                    padding="var(--ggui-spacing-2, 8px)"
                    radius="sm"
                    shadow={isSelected ? 'md' : 'none'}
                    border={true}
                    style={{
                      height: '84px',
                      display: 'flex',
                      flexDirection: 'column',
                      justifyContent: 'space-between',
                      position: 'relative',
                      overflow: 'hidden',
                      backgroundColor: isSelected ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    }}
                  >
                    <Text size="xs" weight="bold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {el.atomicNumber}
                    </Text>

                    <Box style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', flex: 1 }}>
                      <Text 
                        size="xl" 
                        weight="bold" 
                        color={isSelected ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurface, #18181b)'}
                      >
                        {el.symbol}
                      </Text>
                    </Box>

                    {/* Visual indicator of category */}
                    <Box
                      style={{
                        position: 'absolute',
                        bottom: 0,
                        left: 0,
                        right: 0,
                        height: '4px',
                        backgroundColor: bgColor
                      }}
                    />
                  </Card>
                </div>
              );
            })}
          </div>
        </Box>

        <Divider margin={8} />

        {/* Detailed Inspection Panel */}
        {selectedElement ? (
          <Box style={{ animation: 'ggui-slideInUp 300ms ease-out' }}>
            <Card padding="var(--ggui-spacing-8, 32px)" shadow="md" radius="xl" border={true} style={{ backgroundColor: 'var(--ggui-color-surface, #fafafa)' }}>
              <Stack direction="horizontal" gap="var(--ggui-spacing-12, 48px)" align="start" wrap>
                {/* Hero Box for the Element */}
                <Box 
                  padding="var(--ggui-spacing-12, 48px)" 
                  style={{ 
                    minWidth: '240px', 
                    textAlign: 'center',
                    backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                    borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
                    border: '2px solid var(--ggui-color-primary-200, #bae6fd)',
                    boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'
                  }}
                >
                  <Text style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', lineHeight: 1 }} weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
                    {selectedElement.symbol}
                  </Text>
                  <Text variant="overline" color="var(--ggui-color-primary-700, #0369a1)">
                    Atomic No. {selectedElement.atomicNumber}
                  </Text>
                </Box>

                {/* Properties List */}
                <Stack gap="var(--ggui-spacing-6, 24px)" style={{ flex: 1 }}>
                  <Stack gap="var(--ggui-spacing-2, 8px)">
