import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Text, Heading } from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-100)',
  'noble-gas': 'var(--ggui-color-info-100)',
  'alkali-metal': 'var(--ggui-color-error-100)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100)',
  'halogen': 'var(--ggui-color-success-100)',
  'transition-metal': 'var(--ggui-color-neutral-100)',
};

export default function GeneratedComponent(props: Props) {
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);
  const [search, setSearch] = useState('');

  const filtered = useMemo(() => 
    props.elements.filter((el) =>
      el.name?.toLowerCase().includes(search.toLowerCase()) ||
      el.symbol?.toLowerCase().includes(search.toLowerCase())
    ), [props.elements, search]);

  const categories = useMemo(() => 
    Array.from(new Set(props.elements.map((e) => e.category).filter((c): c is string => !!c))),
  [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Heading level={1}>Periodic Table</Heading>

        <SearchField
          value={search}
          onChange={setSearch}
          placeholder="Search by name or symbol..."
        />

        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, 1fr)', 
          gap: 'var(--ggui-spacing-1, 4px)', 
          alignItems: 'start' 
        }} role="grid">
          {props.elements.map((el, i) => {
            const isMatch = filtered.includes(el);
            return (
              <div
                key={i}
                style={{ gridRow: el.row, gridColumn: el.col, opacity: isMatch ? 1 : 0.2, transition: 'opacity 200ms ease' }}
                role="gridcell"
                tabIndex={0}
                aria-label={`${el.name}, Atomic Number ${el.atomicNumber}`}
              >
                <button
                  type="button"
                  style={{
                    all: 'unset',
                    display: 'block',
                    width: '100%',
                    cursor: 'pointer'
                  }}
                  onClick={() => setSelected(el)}
                >
                  <Card
                    padding="var(--ggui-spacing-2, 8px)"
                    radius="sm"
                    border={true}
                    style={{
                      background: el.category ? (CATEGORY_COLORS[el.category] ?? 'var(--ggui-color-surfaceVariant)') : 'var(--ggui-color-surfaceVariant)',
                      transition: 'background 200ms ease'
                    }}
                  >
                    <Text variant="caption">{el.atomicNumber}</Text>
                    <Heading level={4} align="center">{el.symbol}</Heading>
                  </Card>
                </button>
              </div>
            );
          })}
        </div>

        {selected && (
          <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={2}>{selected.name}</Heading>
              <Text>Symbol: {selected.symbol}</Text>
              <Text>Atomic Number: {selected.atomicNumber}</Text>
              <Text>Atomic Weight: {selected.atomicWeight}</Text>
              <Text>Category: {selected.category}</Text>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" gap="var(--ggui-spacing-3, 12px)" wrap>
          {categories.map((cat) => (
            <Box key={cat} paddingX="var(--ggui-spacing-2, 8px)" paddingY="var(--ggui-spacing-1, 4px)" borderRadius="var(--ggui-shape-radius-full, 9999px)" style={{ background: CATEGORY_COLORS[cat] }}>
              <Text variant="caption" weight="medium">{cat}</Text>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

