import React, { useState, useMemo, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Input, 
  Divider 
} from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-200)',
  'noble-gas': 'var(--ggui-color-info-200)',
  'alkali-metal': 'var(--ggui-color-warning-200)',
  'halogen': 'var(--ggui-color-error-200)',
  'transition-metal': 'var(--ggui-color-success-200)',
};

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      console.log('Received agent data:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(q) ||
        el.symbol?.toLowerCase().includes(q)
    );
  }, [searchQuery, props.elements]);

  const categories = Array.from(
    new Set(props.elements.map((e) => e.category || 'other'))
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Input
          label="Search Element"
          placeholder="Search by name or symbol..."
          value={searchQuery}
          onChange={(val) => setSearchQuery(val)}
        />

        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))', 
            gap: 'var(--ggui-spacing-1, 4px)' 
          }}
          role="grid"
        >
          {filteredElements.map((el) => (
            <div
              key={el.atomicNumber}
              role="gridcell"
              tabIndex={0}
              onClick={() => setSelectedElement(el)}
              onKeyDown={(e) => e.key === 'Enter' && setSelectedElement(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                background: el.category 
                  ? CATEGORY_COLORS[el.category] ?? 'var(--ggui-color-neutral-200)' 
                  : 'var(--ggui-color-neutral-200)',
                cursor: 'pointer',
                textAlign: 'center',
                transition: 'all 200ms ease-out',
                position: 'relative',
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                padding: 'var(--ggui-spacing-1, 4px)',
                minHeight: '60px',
                border: selectedElement?.atomicNumber === el.atomicNumber 
                  ? '2px solid var(--ggui-color-primary-600)' 
                  : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
              }}
              aria-selected={selectedElement?.atomicNumber === el.atomicNumber}
            >
              <Text variant="caption" style={{ position: 'absolute', top: 2, left: 4 }}>
                {el.atomicNumber}
              </Text>
              <Text variant="bodyLarge" style={{ fontWeight: 'var(--ggui-font-weight-bold, 700)', marginTop: '12px' }}>
                {el.symbol}
              </Text>
            </div>
          ))}
        </Box>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>{selectedElement.name}</Heading>
              <Text variant="body">Symbol: {selectedElement.symbol}</Text>
              <Text variant="body">Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text variant="body">Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text variant="body">Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}

        <Divider margin="var(--ggui-spacing-4, 16px)" />

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {categories.map((cat) => (
            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center" key={cat}>
              <Box style={{ 
                width: 16, 
                height: 16, 
                background: CATEGORY_COLORS[cat] ?? 'var(--ggui-color-neutral-200)', 
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)' 
              }} />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Container, Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  // Example: "Tokyo"
  /** Current temperature */
  temperature: number;
  // Example: 28
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  // Example: "Sunny"
  /** Humidity percentage */
  humidity: number;
  // Example: 45
  /** Wind speed */
  windSpeed: number;
  // Example: 8
  /** Temperature unit (C or F) */
  unit?: string;
  // Example: "C"
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
  // Example: [
  //   {
  //     "day": "Mon",
  //     "icon": "☀️",
  //     "high": 30,
  //     "low": 22
  //   },
  //   {
  //     "day": "Tue",
  //     "icon": "⛅",
  //     "high": 27,
  //     "low": 20
  //   }
  // ]
}

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  const mutedTextColor =
    'var(--ggui-color-onSurfaceVariant, var(--ggui-color-neutral-500, #6b7280))';
  const primaryTextColor = 'var(--ggui-color-onSurface, var(--ggui-color-neutral-900, #111827))';
  const surfaceVariantBg = 'var(--ggui-color-surfaceVariant, var(--ggui-color-neutral-100, #f3f4f6))';
  const outlineVariant = 'var(--ggui-color-outlineVariant, var(--ggui-color-outline, #e4e4e7))';

  const unitSuffix = unit != null ? `°${unit}` : '';
  const unitDisplay = unit != null ? ` ${unit}` : '';
  const currentIcon = forecast?.[0]?.icon ?? '';

  const forecastItems = (forecast ?? []).slice(0, 5);

  const fmtTemp = (value: number | undefined) => (value == null ? '—' : `${value}`);

  const ariaSummary = `Weather in ${city}: ${temperature}${unitSuffix} and ${condition}.`;

  return (
    <Container maxWidth="md">
      <Card
        shadow="sm"
        radius="lg"
        padding={24}
        border
        style={{ background: surfaceVariantBg }}
        aria-label={ariaSummary}
      >
        <Stack gap={16}>
          <Stack direction="horizontal" justify="between" align="center" gap={16}>
            <Stack direction="vertical" gap={6} align="start">
              <Text variant="label" color={mutedTextColor}>
                {city}
              </Text>

              <Stack direction="horizontal" gap={8} align="center">
                <Heading level={2} color={primaryTextColor}>
                  {temperature}
                  {unitSuffix ? <Text variant="bodySmall" color={primaryTextColor} as="span">{unitSuffix}</Text> : null}
                </Heading>
              </Stack>

              <Stack direction="horizontal" gap={8} align="center">
                <Text variant="bodySmall" color={mutedTextColor} as="span" aria-hidden={true}>
                  {currentIcon || '—'}
                </Text>
                <Text variant="bodyLarge" color={primaryTextColor}>
                  {condition}
                </Text>
              </Stack>
            </Stack>

            <Stack direction="vertical" gap={8} align="end">
              <Stack direction="horizontal" gap={8} justify="between" align="center">
                <Text variant="caption" color={mutedTextColor}>
                  Humidity
                </Text>
                <Text variant="bodySmall" color={primaryTextColor} weight="semibold">
                  {humidity}
                  <Text variant="bodySmall" color={mutedTextColor} weight="normal" as="span">
                    %
                  </Text>
                </Text>
              </Stack>

              <Stack direction="horizontal" gap={8} justify="between" align="center">
                <Text variant="caption" color={mutedTextColor}>
                  Wind
                </Text>
                <Text variant="bodySmall" color={primaryTextColor} weight="semibold">
                  {windSpeed}
                </Text>
              </Stack>
            </Stack>
          </Stack>

          <Divider margin={16} />

          <Stack direction="horizontal" gap={8} wrap={true} justify="between" align="stretch">
            {forecastItems.length > 0 ? (
              forecastItems.map((f, idx) => {
                const dayDisplay = f.day ?? '—';
                const iconDisplay = f.icon ?? '—';
                const highDisplay = fmtTemp(f.high);
                const lowDisplay = fmtTemp(f.low);

                return (
                  <Stack
                    key={`${dayDisplay}-${idx}`}
                    direction="vertical"
                    gap={4}
                    align="center"
                    style={{
                      flex: '1 1 0',
                      minWidth: 0,
                      padding: 'var(--ggui-spacing-2, 8px)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      background: 'var(--ggui-color-surface, var(--ggui-color-surfaceVariant, var(--ggui-color-neutral-100, #f3f4f6)))',
                      border: `1px solid var(--ggui-color-outlineVariant, ${outlineVariant})`,
                    }}
                  >
                    <Text variant="caption" color={mutedTextColor}>
                      {dayDisplay}
                    </Text>

                    <Text variant="bodySmall" color={mutedTextColor} as="span" aria-hidden={true}>
                      {iconDisplay}
                    </Text>

                    <Stack direction="horizontal" gap={8} align="center">
                      <Text variant="bodySmall" color={primaryTextColor} weight="semibold">
                        {highDisplay}
                        {unit != null ? <Text variant="bodySmall" color={mutedTextColor} as="span">°{unit}</Text> : null}
                      </Text>
                      <Text variant="bodySmall" color={mutedTextColor} as="span">
                        /
                      </Text>
                      <Text variant="bodySmall" color={primaryTextColor} weight="semibold">
                        {lowDisplay}
                        {unit != null ? <Text variant="bodySmall" color={mutedTextColor} as="span">°{unit}</Text> : null}
                      </Text>
                    </Stack>
                  </Stack>
                );
              })
            ) : (
              <Stack direction="horizontal" justify="center" align="center" gap={8}>
                <Text variant="bodySmall" color={mutedTextColor}>
                  No forecast available
                </Text>
              </Stack>
            )}
          </Stack>

          <Text variant="bodySmall" color={mutedTextColor} as="p">
            {temperature}
            {unitSuffix ? unitSuffix : ''} in {city}: {condition}
            {unitDisplay ? unitDisplay : ''}
          </Text>
        </Stack>
      </Card>
    </Container>
  );
}

