  windSpeed: number;
  unit?: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getWeatherVisual(condition: string): string {
  const normalized = condition.trim().toLowerCase();
  if (normalized.includes('thunder') || normalized.includes('storm')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('hail')) return '❄️';
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
  if (normalized.includes('cloud') || normalized.includes('overcast') || normalized.includes('mist') || normalized.includes('fog')) return '☁️';
  if (normalized.includes('partly') || normalized.includes('haze') || normalized.includes('wind')) return '⛅';
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  return '🌤️';
}

function formatTemp(value: number | string, unit: string): string {
  return `${value}${typeof value === 'number' ? '°' : ''} ${unit}`;
}

