import React, { useEffect, useMemo, useState } from "react";
import { Badge, Box, Button, Card, Container, Divider, Heading, Icon, Input, MotionKeyframes, Stack, Text } from "@ggui-ai/design/primitives";

interface Props {
  /** Full periodic table element data */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

type ElementData = Props["elements"][number];

type CategoryMeta = {
  label: string;
  background: string;
  foreground: string;
  border: string;
};

type NormalizedElement = ElementData & {
  key: string;
  displayName: string;
  displaySymbol: string;
  displayAtomicNumber: string;
  displayAtomicWeight: string;
  displayCategory: string;
  rowValue: number;
  colValue: number;
  categoryKey: string;
};

const CATEGORY_META: Record<string, CategoryMeta> = {
  "alkali-metal": {
    label: "Alkali metal",
    background: "var(--ggui-color-primary-50, #f0f9ff)",
    foreground: "var(--ggui-color-primary-700, #0369a1)",
    border: "var(--ggui-color-primary-200, #bae6fd)",
  },
  "alkaline-earth-metal": {
    label: "Alkaline earth metal",
    background: "var(--ggui-color-info-50, #ecfeff)",
