    background: "var(--ggui-color-info-100, #cffafe)",
    foreground: "var(--ggui-color-info-700, #0e7490)",
    border: "var(--ggui-color-info-200, #a5f3fc)",
  },
  lanthanoid: {
    label: "Lanthanoid",
    background: "var(--ggui-color-container, #ede9fe)",
    foreground: "var(--ggui-color-onContainer, #4c1d95)",
    border: "var(--ggui-color-primary-200, #bae6fd)",
  },
  actinoid: {
    label: "Actinoid",
    background: "var(--ggui-color-warning-100, #fef3c7)",
    foreground: "var(--ggui-color-warning-700, #b45309)",
    border: "var(--ggui-color-warning-200, #fde68a)",
  },
  unknown: {
    label: "Unknown",
    background: "var(--ggui-color-surfaceVariant, #f4f4f5)",
    foreground: "var(--ggui-color-onSurfaceVariant, #52525b)",
    border: "var(--ggui-color-outlineVariant, #e4e4e7)",
  },
};

function normalizeCategory(category?: string): string {
  return (category ?? "unknown").trim().toLowerCase() || "unknown";
}

function toDisplayWeight(weight?: number): string {
  return weight ?? weight === 0 ? String(weight) : "—";
}

function toDisplayNumber(value?: number): string {
  return value ?? value === 0 ? String(value) : "—";
}

function getCategoryMeta(category?: string): CategoryMeta {
  const key = normalizeCategory(category);
  return CATEGORY_META[key] ?? CATEGORY_META.unknown;
}

function getElementKey(element: ElementData, index: number): string {
  if (element.atomicNumber ?? null) return `atomic-${element.atomicNumber}`;
  const symbol = (element.symbol ?? "").trim();
  const name = (element.name ?? "").trim();
  return `${symbol || "element"}-${name || "unnamed"}-${index}`;
}

function sortGridElements(elements: NormalizedElement[]): NormalizedElement[] {
  return [...elements].sort((a, b) => {
    const rowDiff = a.rowValue - b.rowValue;
    if (rowDiff !== 0) return rowDiff;
    const colDiff = a.colValue - b.colValue;
    if (colDiff !== 0) return colDiff;
    return a.key.localeCompare(b.key);
  });
}

function formatCategoryLabel(category?: string): string {
  return getCategoryMeta(category).label;
}

function InfoField(props: { label: string; value: string | number }) {
  return (
    <Card shadow="none" padding="var(--ggui-spacing-4, 16px)" radius="md" border>
      <Stack gap="var(--ggui-spacing-1, 4px)">
        <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {props.label}
        </Text>
        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
          {String(props.value ?? "—")}
        </Text>
      </Stack>
    </Card>
  );
}

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState<string>("");
  const [selectedKey, setSelectedKey] = useState<string | null>(null);

  useEffect(() => {
    const onStream = (event: Event) => {
      const customEvent = event as CustomEvent<{ searchQuery?: string; selectedKey?: string }>;
      const detail = customEvent.detail;
      if (detail?.searchQuery !== undefined) setSearchQuery(detail.searchQuery);
      if (detail?.selectedKey !== undefined) setSelectedKey(detail.selectedKey);
    };
    window.addEventListener("ggui:agent-data", onStream as EventListener);
    return () => window.removeEventListener("ggui:agent-data", onStream as EventListener);
  }, []);

  const normalizedElements = useMemo<NormalizedElement[]>(() => {
    return props.elements.map((element, index) => ({
      ...element,
      key: getElementKey(element, index),
      displayName: element.name ?? "—",
      displaySymbol: element.symbol ?? "—",
      displayAtomicNumber: toDisplayNumber(element.atomicNumber),
      displayAtomicWeight: toDisplayWeight(element.atomicWeight),
      displayCategory: formatCategoryLabel(element.category),
      rowValue: element.row ?? 0,
      colValue: element.col ?? 0,
      categoryKey: normalizeCategory(element.category),
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    const filtered = query.length
      ? normalizedElements.filter((element) => {
          const name = (element.name ?? "").toLowerCase();
          const symbol = (element.symbol ?? "").toLowerCase();
          return name.includes(query) || symbol.includes(query);
        })
      : normalizedElements;
    return sortGridElements(filtered);
  }, [normalizedElements, searchQuery]);

  useEffect(() => {
    if (normalizedElements.length === 0) {
      setSelectedKey(null);
      return;
    }
    const existingSelected = selectedKey ? normalizedElements.find((el) => el.key === selectedKey) : null;
    if (existingSelected) return;
    setSelectedKey(normalizedElements[0].key);
  }, [normalizedElements, selectedKey]);

  const selectedElement = useMemo(() => {
    if (!selectedKey) return filteredElements[0] ?? normalizedElements[0] ?? null;
    return normalizedElements.find((element) => element.key === selectedKey) ?? filteredElements[0] ?? normalizedElements[0] ?? null;
  }, [filteredElements, normalizedElements, selectedKey]);

  const legendCategories = useMemo(() => {
    const seen = new Set<string>();
    const items: Array<{ key: string; meta: CategoryMeta }> = [];
    normalizedElements.forEach((element) => {
      const key = element.categoryKey;
      if (seen.has(key)) return;
      seen.add(key);
      items.push({ key, meta: getCategoryMeta(element.category) });
    });
    if (!seen.has("unknown")) items.push({ key: "unknown", meta: CATEGORY_META.unknown });
    return items;
  }, [normalizedElements]);

  const hasResults = filteredElements.length > 0;
  const selectedMeta = selectedElement ? getCategoryMeta(selectedElement.category) : CATEGORY_META.unknown;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
                Periodic Table
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Search by name or symbol, then select an element to view its details.
              </Text>
            </Stack>

            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" align="end" wrap>
              <Box style={{ flex: "1 1 320px" } as React.CSSProperties}>
                <Input
                  label="Search elements"
                  type="search"
                  value={searchQuery}
                  onChange={setSearchQuery}
                  placeholder="Hydrogen, H, noble gas..."
                />
              </Box>
              {searchQuery.trim().length > 0 ? (
                <Button variant="ghost" size="sm" onClick={() => setSearchQuery("")} aria-label="Clear search">
                  <Icon name="x" size={16} />
                  Clear
                </Button>
              ) : null}
            </Stack>

            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Legend
              </Text>
              <Box
                style={{
                  display: "flex",
                  flexWrap: "wrap",
                  gap: "var(--ggui-spacing-2, 8px)",
                }}
              >
                {legendCategories.map((entry) => (
                  <Badge
                    key={entry.key}
                    variant="default"
                    size="sm"
                    pill
                    style={{
                      backgroundColor: entry.meta.background,
                      color: entry.meta.foreground,
                      border: `1px solid ${entry.meta.border}`,
                    } as React.CSSProperties}
                  >
                    {entry.meta.label}
                  </Badge>
                ))}
              </Box>
            </Stack>
          </Stack>
        </Card>

        <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Stack gap="var(--ggui-spacing-1, 4px)">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Element Grid
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                18-column layout positioned by each element&apos;s row and column data.
              </Text>
            </Stack>

            <Box style={{ overflowX: "auto", paddingBottom: "var(--ggui-spacing-1, 4px)" }}>
              <Box
                style={{
                  display: "grid",
                  gridTemplateColumns: "repeat(18, minmax(0, 1fr))",
                  gap: "var(--ggui-spacing-1, 4px)",
                  minWidth: "980px",
                }}
              >
                {hasResults ? (
                  filteredElements.map((element) => {
                    const meta = getCategoryMeta(element.category);
                    const isSelected = selectedElement?.key === element.key;
                    const hasPlacement = element.rowValue > 0 && element.colValue > 0;
                    return (
                      <button
                        key={element.key}
                        type="button"
                        onClick={() => setSelectedKey(element.key)}
                        aria-pressed={isSelected}
                        aria-label={`${element.name ?? "Unknown"}, ${element.symbol ?? "—"}, atomic number ${element.atomicNumber ?? "—"}, ${element.category ?? "unknown"}`}
                        style={{
                          gridRow: hasPlacement ? String(element.rowValue) : "auto",
                          gridColumn: hasPlacement ? String(element.colValue) : "auto",
                          minHeight: "var(--ggui-spacing-12, 48px)",
                          padding: "var(--ggui-spacing-1, 4px)",
                          borderRadius: "var(--ggui-shape-radius-md, 8px)",
                          border: `1px solid ${isSelected ? "var(--ggui-color-primary-600, #0284c7)" : meta.border}`,
                          backgroundColor: meta.background,
                          color: meta.foreground,
                          cursor: "pointer",
                          transition:
                            "transform 200ms ease-in-out, box-shadow 200ms ease-in-out, border-color 200ms ease-in-out, background-color 200ms ease-in-out",
                          outline: "none",
                          boxShadow: isSelected ? "var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))" : "none",
                          display: "flex",
                          flexDirection: "column",
                          justifyContent: "space-between",
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.transform = "translateY(-1px)";
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.transform = "translateY(0)";
                        }}
                      >
                        <Text variant="caption" weight="semibold" color={meta.foreground} style={{ alignSelf: "flex-start" }}>
                          {element.displayAtomicNumber}
                        </Text>
                        <Text
                          variant="bodyLarge"
                          weight="bold"
                          color={meta.foreground}
                          align="center"
                          style={{
                            lineHeight: 1,
                            minHeight: "var(--ggui-spacing-6, 24px)",
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                          }}
                        >
                          {element.displaySymbol}
                        </Text>
                        <Text variant="caption" color={meta.foreground} align="center" truncate as="div">
                          {element.name ?? "—"}
                        </Text>
                      </button>
                    );
                  })
                ) : (
                  <Box
                    style={{
                      gridColumn: "1 / -1",
                      padding: "var(--ggui-spacing-8, 32px)",
                      textAlign: "center",
                      border: "1px dashed var(--ggui-color-outline, #d4d4d8)",
                      borderRadius: "var(--ggui-shape-radius-lg, 12px)",
                      backgroundColor: "var(--ggui-color-surface, #fafafa)",
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
                      <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        No matching elements
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Try a different name or symbol.
                      </Text>
                    </Stack>
                  </Box>
                )}
              </Box>
            </Box>
          </Stack>
        </Card>

