import React, { useMemo } from 'react';
import { Card, Stack, Box, Text, Heading, Divider, Badge, MotionKeyframes } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function conditionVisual(condition: string): { icon: string; tone: string } {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return { icon: '☀️', tone: 'primary' };
  if (normalized.includes('cloud') || normalized.includes('overcast')) return { icon: '☁️', tone: 'default' };
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return { icon: '🌧️', tone: 'info' };
  if (normalized.includes('storm') || normalized.includes('thunder')) return { icon: '⛈️', tone: 'error' };
  if (normalized.includes('snow')) return { icon: '🌨️', tone: 'info' };
  if (normalized.includes('fog') || normalized.includes('mist')) return { icon: '🌫️', tone: 'secondary' };
  if (normalized.includes('wind')) return { icon: '💨', tone: 'default' };
  return { icon: '⛅', tone: 'default' };
}

function formatMaybeTemp(value: number | undefined, unit: string): string {
  return typeof value === 'number' ? `${value}°${unit}` : '—';
}

