import React, { useEffect, useMemo, useState } from 'react';
import { Badge, Box, Button, Card, Container, Divider, Heading, Icon, Input, MotionKeyframes, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

type ElementItem = Props['elements'][number];
type BadgeVariant = 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info';

const categoryVariantMap: Record<string, BadgeVariant> = {
  'noble-gas': 'info',
  halogen: 'warning',
  'alkali-metal': 'error',
  'alkaline-earth-metal': 'primary',
  'transition-metal': 'secondary',
  'post-transition-metal': 'default',
  metalloid: 'primary',
  nonmetal: 'success',
  lanthanide: 'info',
  actinide: 'warning',
  unknown: 'default',
  uncategorized: 'default',
};

function normalizeCategory(value?: string): string {
  return (value ?? 'uncategorized').trim().toLowerCase() || 'uncategorized';
}

function humanizeCategory(value?: string): string {
  const normalized = normalizeCategory(value);
  return normalized
    .split('-')
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ');
}

function formatAtomicWeight(value?: number): string {
  return value ?? value === 0 ? String(value) : '—';
}

function formatNumberLabel(value?: number): string {
  return value ?? value === 0 ? String(value) : '—';
}

function getVariantForCategory(category?: string): BadgeVariant {
  return categoryVariantMap[normalizeCategory(category)] ?? 'default';
}

function getCategoryToken(category?: string): { accent: string; tint: string; border: string; text: string; selected: string } {
  const normalized = normalizeCategory(category);
  switch (normalized) {
    case 'noble-gas':
      return {
        accent: 'var(--ggui-color-info-500, var(--ggui-color-primary-500, currentColor))',
        tint: 'var(--ggui-color-info-50, var(--ggui-color-primary-50, var(--ggui-color-surfaceVariant, currentColor)))',
        border: 'var(--ggui-color-info-200, var(--ggui-color-primary-200, var(--ggui-color-outline, currentColor)))',
        text: 'var(--ggui-color-info-800, var(--ggui-color-onSurface, currentColor))',
        selected: 'var(--ggui-color-info-100, var(--ggui-color-primary-50, var(--ggui-color-surfaceVariant, currentColor)))',
      };
    case 'halogen':
      return {
        accent: 'var(--ggui-color-warning-500, var(--ggui-color-warning-600, currentColor))',
        tint: 'var(--ggui-color-warning-50, var(--ggui-color-surfaceVariant, currentColor))',
        border: 'var(--ggui-color-warning-200, var(--ggui-color-outline, currentColor))',
        text: 'var(--ggui-color-warning-800, var(--ggui-color-onSurface, currentColor))',
        selected: 'var(--ggui-color-warning-100, var(--ggui-color-primary-50, currentColor))',
      };
    case 'alkali-metal':
      return {
        accent: 'var(--ggui-color-error-500, var(--ggui-color-error-600, currentColor))',
        tint: 'var(--ggui-color-error-50, var(--ggui-color-surfaceVariant, currentColor))',
        border: 'var(--ggui-color-error-200, var(--ggui-color-outline, currentColor))',
        text: 'var(--ggui-color-error-800, var(--ggui-color-onSurface, currentColor))',
        selected: 'var(--ggui-color-error-100, var(--ggui-color-primary-50, currentColor))',
      };
    case 'alkaline-earth-metal':
      return {
        accent: 'var(--ggui-color-primary-600, var(--ggui-color-primary-500, currentColor))',
        tint: 'var(--ggui-color-primary-50, var(--ggui-color-surfaceVariant, currentColor))',
        border: 'var(--ggui-color-primary-200, var(--ggui-color-outline, currentColor))',
        text: 'var(--ggui-color-onSurface, currentColor)',
        selected: 'var(--ggui-color-primary-100, var(--ggui-color-surfaceVariant, currentColor))',
      };
    case 'transition-metal':
      return {
        accent: 'var(--ggui-color-neutral-500, var(--ggui-color-outline, currentColor))',
        tint: 'var(--ggui-color-surfaceVariant, currentColor)',
        border: 'var(--ggui-color-outlineVariant, currentColor)',
        text: 'var(--ggui-color-onSurface, currentColor)',
        selected: 'var(--ggui-color-primary-50, currentColor)',
      };
    case 'post-transition-metal':
      return {
        accent: 'var(--ggui-color-neutral-700, var(--ggui-color-outline, currentColor))',
        tint: 'var(--ggui-color-surfaceVariant, currentColor)',
        border: 'var(--ggui-color-outlineVariant, currentColor)',
        text: 'var(--ggui-color-onSurface, currentColor)',
        selected: 'var(--ggui-color-primary-50, currentColor)',
      };
    case 'metalloid':
      return {
        accent: 'var(--ggui-color-primary-500, var(--ggui-color-info-500, currentColor))',
        tint: 'var(--ggui-color-primary-50, var(--ggui-color-surfaceVariant, currentColor))',
        border: 'var(--ggui-color-primary-200, var(--ggui-color-outline, currentColor))',
        text: 'var(--ggui-color-primary-800, var(--ggui-color-onSurface, currentColor))',
        selected: 'var(--ggui-color-primary-100, var(--ggui-color-primary-50, currentColor))',
      };
    case 'nonmetal':
      return {
        accent: 'var(--ggui-color-success-500, var(--ggui-color-success-600, currentColor))',
        tint: 'var(--ggui-color-success-50, var(--ggui-color-surfaceVariant, currentColor))',
        border: 'var(--ggui-color-success-200, var(--ggui-color-outline, currentColor))',
        text: 'var(--ggui-color-success-800, var(--ggui-color-onSurface, currentColor))',
        selected: 'var(--ggui-color-success-100, var(--ggui-color-primary-50, currentColor))',
      };
    case 'lanthanide':
      return {
        accent: 'var(--ggui-color-info-500, var(--ggui-color-primary-500, currentColor))',
        tint: 'var(--ggui-color-info-50, var(--ggui-color-surfaceVariant, currentColor))',
        border: 'var(--ggui-color-info-200, var(--ggui-color-outline, currentColor))',
        text: 'var(--ggui-color-info-800, var(--ggui-color-onSurface, currentColor))',
        selected: 'var(--ggui-color-info-100, var(--ggui-color-primary-50, currentColor))',
      };
    case 'actinide':
      return {
        accent: 'var(--ggui-color-warning-600, var(--ggui-color-warning-500, currentColor))',
        tint: 'var(--ggui-color-warning-50, var(--ggui-color-surfaceVariant, currentColor))',
        border: 'var(--ggui-color-warning-200, var(--ggui-color-outline, currentColor))',
        text: 'var(--ggui-color-warning-800, var(--ggui-color-onSurface, currentColor))',
        selected: 'var(--ggui-color-warning-100, var(--ggui-color-primary-50, currentColor))',
      };
    default:
      return {
        accent: 'var(--ggui-color-outline, currentColor)',
        tint: 'var(--ggui-color-surfaceVariant, currentColor)',
        border: 'var(--ggui-color-outlineVariant, currentColor)',
        text: 'var(--ggui-color-onSurface, currentColor)',
        selected: 'var(--ggui-color-primary-50, currentColor)',
      };
  }
}

function getDisplayName(element: ElementItem): string {
  return element.name ?? 'Unknown element';
}

function getUniqueCategories(elements: ElementItem[]): string[] {
  const seen = new Set<string>();
  const ordered: string[] = [];
  for (const element of elements) {
    const category = normalizeCategory(element.category);
    if (!seen.has(category)) {
      seen.add(category);
      ordered.push(category);
    }
  }
  return ordered;
}

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementItem | null>(null);
  const elements = props.elements ?? [];

  useEffect(() => {
    if (selectedElement == null) return;
    const stillExists = elements.some(
      (element) =>
        element.atomicNumber === selectedElement.atomicNumber &&
        element.symbol === selectedElement.symbol &&
        element.name === selectedElement.name
    );
    if (!stillExists) setSelectedElement(null);
  }, [elements, selectedElement]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) return elements;
    return elements.filter((element) => {
      const name = (element.name ?? '').toLowerCase();
      const symbol = (element.symbol ?? '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [elements, searchQuery]);

  const categoryOrder = useMemo(() => getUniqueCategories(elements), [elements]);
  const selected = selectedElement;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack gap="var(--ggui-spacing-1, 4px)">
          <Heading level={2} color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
            Periodic Table of Elements
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
            Search by name or symbol, then select an element to inspect its details.
          </Text>
        </Stack>

        <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" radius="lg">
          <Input
            label="Search elements"
            type="search"
            value={searchQuery}
            onChange={setSearchQuery}
            placeholder="Search by name or symbol"
            helperText="Case-insensitive filtering across names and symbols."
            aria-label="Search elements"
          />
        </Card>

        <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" radius="lg">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-2, 8px)" wrap>
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Heading level={4} color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                  Periodic Grid
                </Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                  18-column grid positioned by each element&apos;s row and column.
                </Text>
              </Stack>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                {filteredElements.length} element{filteredElements.length === 1 ? '' : 's'} shown
              </Text>
            </Stack>

            {elements.length === 0 ? (
              <Box
                padding="var(--ggui-spacing-8, 32px)"
                background="var(--ggui-color-primary-50, var(--ggui-color-surfaceVariant, currentColor))"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
              >
                <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
                  <Icon name="settings" size={28} color="var(--ggui-color-primary-600, currentColor)" />
                  <Text variant="bodyLarge" align="center" color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                    No elements to display.
                  </Text>
                  <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                    Provide periodic table data through props.elements to render the grid.
                  </Text>
                </Stack>
              </Box>
            ) : filteredElements.length === 0 ? (
              <Box
                padding="var(--ggui-spacing-8, 32px)"
                background="var(--ggui-color-primary-50, var(--ggui-color-surfaceVariant, currentColor))"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
              >
                <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
                  <Icon name="search" size={28} color="var(--ggui-color-primary-600, currentColor)" />
                  <Text variant="bodyLarge" align="center" color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                    No matching elements found.
                  </Text>
                  <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                    Try a different symbol or spelling.
                  </Text>
                </Stack>
              </Box>
            ) : (
              <Box style={{ overflowX: 'auto', overflowY: 'hidden' }}>
                <Box
                  style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(18, minmax(72px, 1fr))',
                    gridAutoRows: '88px',
                    gap: 'var(--ggui-spacing-1, 4px)',
                    minWidth: 'calc(18 * 72px + 17 * var(--ggui-spacing-1, 4px))',
                  }}
                >
                  {filteredElements.map((element, index) => {
                    const atomicNumber = element.atomicNumber ?? 0;
                    const symbol = element.symbol ?? '—';
                    const name = getDisplayName(element);
                    const category = normalizeCategory(element.category);
                    const colors = getCategoryToken(category);
                    const row = element.row ?? 1;
                    const col = element.col ?? 1;
                    const isSelected =
                      selected != null &&
                      selected.atomicNumber === element.atomicNumber &&
                      selected.symbol === element.symbol &&
                      selected.name === element.name;

                    return (
                      <button
                        key={`${atomicNumber}-${symbol}-${index}`}
                        type="button"
                        aria-label={`${name}, atomic number ${formatNumberLabel(element.atomicNumber)}, category ${category}`}
                        aria-pressed={isSelected}
                        onClick={() => setSelectedElement(element)}
                        style={{
                          gridRow: row,
                          gridColumn: col,
                          width: '100%',
                          height: '100%',
                          textAlign: 'left',
                          border: `1px solid ${isSelected ? 'var(--ggui-color-primary-200, var(--ggui-color-outline, currentColor))' : colors.border}`,
                          borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                          background: isSelected ? colors.selected : colors.tint,
                          color: isSelected ? colors.text : 'var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))',
                          boxShadow: isSelected ? 'var(--ggui-shape-shadow-sm)' : 'none',
                          padding: 'var(--ggui-spacing-1, 4px)',
                          cursor: 'pointer',
                          position: 'relative',
                          overflow: 'hidden',
                          transition:
                            'background-color 200ms ease-in-out, border-color 200ms ease-in-out, box-shadow 200ms ease-in-out, transform 200ms ease-in-out',
                          outline: 'none',
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.transform = 'translateY(-1px)';
                          e.currentTarget.style.borderColor = colors.accent;
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.transform = 'translateY(0)';
                          e.currentTarget.style.borderColor = isSelected ? 'var(--ggui-color-primary-200, var(--ggui-color-outline, currentColor))' : colors.border;
                        }}
                        onFocus={(e) => {
                          e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, currentColor)';
                          e.currentTarget.style.outlineOffset = '2px';
                        }}
                        onBlur={(e) => {
                          e.currentTarget.style.outline = 'none';
                        }}
                      >
                        <Box
                          style={{
                            position: 'absolute',
                            insetInlineStart: 0,
                            insetBlockStart: 0,
                            width: '100%',
                            height: '4px',
                            background: colors.accent,
                          }}
                        />
                        <Text
                          variant="caption"
                          color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))"
                          style={{
                            position: 'absolute',
                            top: 'var(--ggui-spacing-1, 4px)',
                            left: 'var(--ggui-spacing-1, 4px)',
                          }}
                        >
                          {formatNumberLabel(element.atomicNumber)}
                        </Text>
                        <Stack
                          align="center"
                          justify="center"
                          style={{
                            height: '100%',
                            paddingTop: 'var(--ggui-spacing-2, 8px)',
                          }}
                        >
                          <Text
                            as="div"
                            variant="bodyLarge"
                            weight="bold"
                            align="center"
                            color={isSelected ? colors.text : 'var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))'}
                            style={{
                              lineHeight: 1,
                              fontSize: 'var(--ggui-font-size-xl, 20px)',
                            }}
                          >
                            {symbol}
                          </Text>
                        </Stack>
                        <Text
                          variant="caption"
                          align="center"
                          truncate
                          color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))"
                          style={{
                            position: 'absolute',
                            left: 'var(--ggui-spacing-1, 4px)',
                            right: 'var(--ggui-spacing-1, 4px)',
                            bottom: 'var(--ggui-spacing-1, 4px)',
                          }}
                        >
                          {humanizeCategory(category)}
                        </Text>
                        {isSelected ? (
                          <Box
                            style={{
                              position: 'absolute',
                              inset: 0,
                              border: '2px solid var(--ggui-color-primary-600, currentColor)',
                              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                              pointerEvents: 'none',
                            }}
                          />
                        ) : null}
                      </button>
                    );
                  })}
                </Box>
              </Box>
            )}
          </Stack>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" radius="lg">
            <Stack gap="var(--ggui-spacing-3, 12px)">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Heading level={4} color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                  Legend
                </Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                  Categories are derived from the supplied dataset.
                </Text>
              </Stack>

              {categoryOrder.length === 0 ? (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                  No categories available.
                </Text>
              ) : (
                <Stack direction="horizontal" wrap gap="var(--ggui-spacing-2, 8px)">
                  {categoryOrder.map((category) => (
                    <Badge key={category} variant={getVariantForCategory(category)} size="sm" pill>
                      {humanizeCategory(category)}
                    </Badge>
                  ))}
                </Stack>
              )}
            </Stack>
          </Card>

          <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" radius="lg">
            <Stack gap="var(--ggui-spacing-3, 12px)">
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Heading level={4} color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                  Element Details
                </Heading>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                  Selected element details
                </Text>
              </Stack>

              {selected ? (
                <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-3, 12px)" wrap>
                      <Box
                        padding="var(--ggui-spacing-3, 12px)"
                        background="var(--ggui-color-primary-50, var(--ggui-color-surfaceVariant, currentColor))"
                        borderRadius="var(--ggui-shape-radius-lg, 12px)"
                      >
                        <Text
                          as="div"
                          variant="bodyLarge"
                          weight="bold"
                          color="var(--ggui-color-primary-700, currentColor)"
                          style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}
                        >
                          {selected.symbol ?? '—'}
                        </Text>
                      </Box>
                      <Stack gap="var(--ggui-spacing-1, 4px)">
                        <Heading level={3} color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                          {selected.name ?? 'Unknown element'}
                        </Heading>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                          {humanizeCategory(selected.category)}
                        </Text>
                      </Stack>
                    </Stack>

                    <Stack direction="horizontal" wrap gap="var(--ggui-spacing-2, 8px)">
                      <Badge variant={getVariantForCategory(selected.category)} size="md" pill>
                        {humanizeCategory(selected.category)}
                      </Badge>
                    </Stack>

                    <Divider margin="var(--ggui-spacing-2, 8px)" />

                    <Stack direction="horizontal" wrap gap="var(--ggui-spacing-4, 16px)">
                      <Box style={{ minWidth: '160px', flex: '1 1 160px' }}>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                          Atomic number
                        </Text>
                        <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                          {formatNumberLabel(selected.atomicNumber)}
                        </Text>
                      </Box>
                      <Box style={{ minWidth: '160px', flex: '1 1 160px' }}>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                          Atomic weight
                        </Text>
                        <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                          {formatAtomicWeight(selected.atomicWeight)}
                        </Text>
                      </Box>
                      <Box style={{ minWidth: '160px', flex: '1 1 160px' }}>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                          Category
                        </Text>
                        <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                          {humanizeCategory(selected.category)}
                        </Text>
                      </Box>
                    </Stack>
                  </Stack>
                </Box>
              ) : (
                <Box
                  padding="var(--ggui-spacing-6, 24px)"
                  background="var(--ggui-color-primary-50, var(--ggui-color-surfaceVariant, currentColor))"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
                    <Icon name="plus" size={28} color="var(--ggui-color-primary-600, currentColor)" />
                    <Text variant="bodyLarge" align="center" color="var(--ggui-color-onSurface, var(--ggui-color-surface, currentColor))">
                      Select an element to view details
                    </Text>
                    <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, var(--ggui-color-surface, currentColor))">
                      Click any periodic table cell to inspect its name, symbol, atomic number, atomic weight, and category.
                    </Text>
                  </Stack>
                </Box>
              )}
            </Stack>
          </Card>
        </Stack>

        {selected ? (
          <Stack direction="horizontal" justify="end">
            <Button variant="ghost" size="sm" onClick={() => setSelectedElement(null)} aria-label="Clear selection">
              Clear selection
            </Button>
          </Stack>
        ) : null}
      </Stack>
    </Container>
  );
}
